module RefModule 
(
  input rst,
  input clk,

  output reg [5:0] count
);

  reg [5:0] unused_binary_count;

  always @(posedge clk or posedge rst) begin
    if (rst) 
	begin
      unused_binary_count <= 6'b000000;
      count <= 6'b000000;
    end 
	else 
	begin
      unused_binary_count <= unused_binary_count + 1;
      count <= (unused_binary_count >> 1) ^ unused_binary_count;
    end
  end

endmodule
